23	}
24	
25	export interface AgentDiff {
26	  path: string;
27	  oldText: string | null;
28	  newText: string;
29	}
30	
31	/**
32	 * An image carried on a synthesized user message update. Structurally
33	 * compatible with AcpPromptImage (defined in state.ts); duplicated here to
34	 * avoid a circular import since state.ts imports AgentUpdate from this file.
35	 */
36	export interface AgentImage {
37	  /** Raw base64 data, no `data:` URL prefix. */
38	  data: string;
39	  mimeType: string;
40	  name?: string;
41	}
42	
43	export type AgentUpdate =
44	  | {
45	      kind: 'message';
46	      role: 'user' | 'assistant';
47	      messageId: string | null;
48	      text: string;
49	      /** Image attachments on synthesized user messages. Not set on real agent events. */
50	      images?: AgentImage[];
51	    }
52	  | {
53	      kind: 'thinking';
54	      messageId: string | null;
55	      text: string;
56	    }
57	  | {
58	      kind: 'tool_call';
59	      toolCallId: string;
60	      title: string;
61	      /** ACP `ToolKind` passthrough ('edit', 'execute', 'think', ...). */
62	      toolKind: string | null;
63	      status: AgentToolStatus | null;
64	      /**
65	       * Tool call id of the parent when this call was produced by a nested
66	       * subagent invocation. `null` in the baseline; provider plugins promote
67	       * vendor `_meta` into this field via `IAcpBehavior.enrich`.
68	       */
69	      parentToolCallId: string | null;
70	      diffs: AgentDiff[];
71	    }
72	  | {
73	      kind: 'tool_update';
74	      toolCallId: string;
75	      title: string | null;
76	      toolKind: string | null;
77	      status: AgentToolStatus | null;
78	      parentToolCallId: string | null;
79	      diffs: AgentDiff[];
80	    }
81	  /**
82	   * Agent execution plan — driven by the ACP stable `plan` session update.
83	   * Entries replace the plan wholesale on each update (ACP semantics).
84	   */
85	  | { kind: 'plan'; entries: AgentPlanEntry[] }
86	  /**
87	   * Catch-all for variants not yet rendered by the client:
88	   * `plan_update` (UNSTABLE/ID-based), `plan_removed` (UNSTABLE/ID-based),
89	   * `available_commands_update`, `current_mode_update`, `config_option_update`,
90	   * `session_info_update`, `usage_update`, and any non-text message/thinking content.
91	   * Preserves today's behaviour (nothing rendered).
92	   */
93	  | { kind: 'ignored' };
94	
95	interface AcpDiffBlock {
96	  path: string;
97	  oldText: string | null;
98	  newText: string;
99	}
100	
101	function extractDiffs(content: ReadonlyArray<ToolCallContent> | null | undefined): AcpDiffBlock[] {
102	  if (!content) return [];
103	  const diffs: AcpDiffBlock[] = [];
104	  for (const block of content) {
105	    if (block.type === 'diff') {
106	      diffs.push({ path: block.path, oldText: block.oldText ?? null, newText: block.newText });
107	    }
108	  }
109	  return diffs;
110	}
111	
112	/**
113	 * Converts a raw ACP `SessionUpdate` into the provider-neutral `AgentUpdate`
114	 * vocabulary.  This function performs all ACP-specific decoding:
115	 *   - Extracts text from `content` blocks for message and thinking variants.
116	 *   - Extracts diff blocks from `ToolCallContent` arrays.
117	 *   - Passes `status` and `kind` through unchanged (no UI-level remapping here).
118	 *   - Sets `parentToolCallId` to `null` (providers enrich this via `IAcpBehavior.enrich`).
119	 *
120	 * Returns `{ kind: 'ignored' }` for variants not yet rendered by the client.
121	 */
122	export function toAgentUpdate(update: SessionUpdate): AgentUpdate {
123	  switch (update.sessionUpdate) {
124	    case 'user_message_chunk': {
125	      if (update.content.type !== 'text' || !update.content.text) return { kind: 'ignored' };
126	      return {
127	        kind: 'message',
128	        role: 'user',
129	        messageId: update.messageId ?? null,
130	        text: update.content.text,
131	      };
132	    }
133	
134	    case 'agent_message_chunk': {
135	      if (update.content.type !== 'text' || !update.content.text) return { kind: 'ignored' };
136	      return {
137	        kind: 'message',
138	        role: 'assistant',
139	        messageId: update.messageId ?? null,
140	        text: update.content.text,
141	      };
142	    }
143	
144	    case 'agent_thought_chunk': {
145	      if (update.content.type !== 'text' || !update.content.text) return { kind: 'ignored' };
146	      return {
147	        kind: 'thinking',
148	        messageId: update.messageId ?? null,
149	        text: update.content.text,
150	      };
151	    }
152	
153	    case 'tool_call': {
154	      return {
155	        kind: 'tool_call',
156	        toolCallId: update.toolCallId,
157	        title: update.title,
158	        toolKind: update.kind ?? null,
159	        status: (update.status as AgentToolStatus | undefined) ?? null,
160	        parentToolCallId: null,
161	        diffs: extractDiffs(update.content),
162	      };
163	    }
164	
165	    case 'tool_call_update': {
166	      return {
167	        kind: 'tool_update',
168	        toolCallId: update.toolCallId,
169	        title: update.title ?? null,
170	        toolKind: update.kind ?? null,
171	        status: (update.status as AgentToolStatus | undefined | null) ?? null,
172	        parentToolCallId: null,
173	        diffs: extractDiffs(update.content ?? undefined),
174	      };
175	    }
176	
177	    case 'plan':
178	      return {
179	        kind: 'plan',
180	        entries: update.entries.map((e) => ({
181	          content: e.content,
182	          status: e.status,
183	          priority: e.priority,
184	        })),
185	      };
186	
187	    // `plan_update` and `plan_removed` are UNSTABLE/ID-based ACP variants gated
188	    // behind PlanCapabilities — not emitted by Claude. Leave as ignored for now.
189	    default:
190	      return { kind: 'ignored' };
191	  }
192	}
