210	// ---------------------------------------------------------------------------
211	// Effects (outputs that the runtime interprets — no I/O inside the machine)
212	// ---------------------------------------------------------------------------
213	
214	export type Effect =
215	  /** Emit the current lifecycle + activeTurnId to the listener. */
216	  | { type: 'state' }
217	  /** Emit a turn update to the listener. */
218	  | { type: 'update'; turnId: string; seq: number; update: AgentUpdate }
219	  /** Commit the turn to history and notify the listener. */
220	  | { type: 'turnCommitted'; turn: AcpTurn }
